detJ(:, 1, 3) = (nds_1_2 .* nds_2_1) ./ 8 - (nds_1_1 .* nds_2_2) ./ 8 + (nds_1_1 .* nds_4_2) ./ 8 - (nds_1_2 .* nds_4_1) ./ 8 - (nds_2_1 .* nds_3_2) ./ 8 + (nds_2_2 .* nds_3_1) ./ 8 - (nds_3_1 .* nds_4_2) ./ 8 + (nds_3_2 .* nds_4_1) ./ 8 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_2_2) ./ 24 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_2_1) ./ 24 - (3 .^ (1 ./ 2) .* nds_1_1 .* nds_4_2) ./ 24 + (3 .^ (1 ./ 2) .* nds_1_2 .* nds_4_1) ./ 24 - (3 .^ (1 ./ 2) .* nds_2_1 .* nds_3_2) ./ 24 + (3 .^ (1 ./ 2) .* nds_2_2 .* nds_3_1) ./ 24 + (3 .^ (1 ./ 2) .* nds_2_1 .* nds_4_2) ./ 12 - (3 .^ (1 ./ 2) .* nds_2_2 .* nds_4_1) ./ 12 - (3 .^ (1 ./ 2) .* nds_3_1 .* nds_4_2) ./ 24 + (3 .^ (1 ./ 2) .* nds_3_2 .* nds_4_1) ./ 24;
detJ(:, 1, 4) = (nds_1_2 .* nds_2_1) ./ 8 - (nds_1_1 .* nds_2_2) ./ 8 + (nds_1_1 .* nds_4_2) ./ 8 - (nds_1_2 .* nds_4_1) ./ 8 - (nds_2_1 .* nds_3_2) ./ 8 + (nds_2_2 .* nds_3_1) ./ 8 - (nds_3_1 .* nds_4_2) ./ 8 + (nds_3_2 .* nds_4_1) ./ 8 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_2_2) ./ 24 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_2_1) ./ 24 - (3 .^ (1 ./ 2) .* nds_1_1 .* nds_3_2) ./ 12 + (3 .^ (1 ./ 2) .* nds_1_2 .* nds_3_1) ./ 12 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_4_2) ./ 24 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_4_1) ./ 24 + (3 .^ (1 ./ 2) .* nds_2_1 .* nds_3_2) ./ 24 - (3 .^ (1 ./ 2) .* nds_2_2 .* nds_3_1) ./ 24 - (3 .^ (1 ./ 2) .* nds_3_1 .* nds_4_2) ./ 24 + (3 .^ (1 ./ 2) .* nds_3_2 .* nds_4_1) ./ 24;

%Stiffness matrix
el_K = zeros(size(els, 1), 12, 12);
el_K(:, 1, 1) = - detJ(:, 1, 2) .* ((D(1, 6) .* ((2 .* (3 .^ (1 ./ 2) ./ 12 - 1 ./ 4) .* (nds_1_2 - nds_2_2 - nds_3_2 + nds_4_2 + (3 .^ (1 ./ 2) .* nds_1_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_2_2) ./ 3 + (3 .^ (1 ./ 2) .* nds_3_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_4_2) ./ 3)) ./ (nds_1_1 .* nds_2_2 - nds_1_2 .* nds_2_1 - nds_1_1 .* nds_4_2 + nds_1_2 .* nds_4_1 + nds_2_1 .* nds_3_2 - nds_2_2 .* nds_3_1 + nds_3_1 .* nds_4_2 - nds_3_2 .* nds_4_1 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_2_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_2_1) ./ 3 - (2 .* 3 .^ (1 ./ 2) .* nds_1_1 .* nds_3_2) ./ 3 + (2 .* 3 .^ (1 ./ 2) .* nds_1_2 .* nds_3_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_4_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_4_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_2_1 .* nds_3_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_2_2 .* nds_3_1) ./ 3 - (3 .^ (1 ./ 2) .* nds_3_1 .* nds_4_2) ./ 3 + (3 .^ (1 ./ 2) .* nds_3_2 .* nds_4_1) ./ 3) + (2 .* (3 .^ (1 ./ 2) ./ 12 + 1 ./ 4) .* (nds_1_2 + nds_2_2 - nds_3_2 - nds_4_2 - (3 .^ (1 ./ 2) .* nds_1_2) ./ 3 + (3 .^ (1 ./ 2) .* nds_2_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_3_2) ./ 3 + (3 .^ (1 ./ 2) .* nds_4_2) ./ 3)) ./ (nds_1_1 .* nds_2_2 - nds_1_2 .* nds_2_1 - nds_1_1 .* nds_4_2 + nds_1_2 .* nds_4_1 + nds_2_1 .* nds_3_2 - nds_2_2 .* nds_3_1 + nds_3_1 .* nds_4_2 - nds_3_2 .* nds_4_1 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_2_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_2_1) ./ 3 - (2 .* 3 .^ (1 ./ 2) .* nds_1_1 .* nds_3_2) ./ 3 + (2 .* 3 .^ (1 ./ 2) .* nds_1_2 .* nds_3_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_4_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_4_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_2_1 .* nds_3_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_2_2 .* nds_3_1) ./ 3 - (3 .^ (1 ./ 2) .* nds_3_1 .* nds_4_2) ./ 3 + (3 .^ (1 ./ 2) .* nds_3_2 .* nds_4_1) ./ 3)) - D(6, 6) .* ((2 .* (3 .^ (1 ./ 2) ./ 12 - 1 ./ 4) .* (nds_1_1 - nds_2_1 - nds_3_1 + nds_4_1 + (3 .^ (1 ./ 2) .* nds_1_1) ./ 3 - (3 .^ (1 ./ 2) .* nds_2_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_3_1) ./ 3 - (3 .^ (1 ./ 2) .* nds_4_1) ./ 3)) ./ (nds_1_1 .* nds_2_2 - nds_1_2 .* nds_2_1 - nds_1_1 .* nds_4_2 + nds_1_2 .* nds_4_1 + nds_2_1 .* nds_3_2 - nds_2_2 .* nds_3_1 + nds_3_1 .* nds_4_2 - nds_3_2 .* nds_4_1 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_2_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_2_1) ./ 3 - (2 .* 3 .^ (1 ./ 2) .* nds_1_1 .* nds_3_2) ./ 3 + (2 .* 3 .^ (1 ./ 2) .* nds_1_2 .* nds_3_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_4_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_4_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_2_1 .* nds_3_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_2_2 .* nds_3_1) ./ 3 - (3 .^ (1 ./ 2) .* nds_3_1 .* nds_4_2) ./ 3 + (3 .^ (1 ./ 2) .* nds_3_2 .* nds_4_1) ./ 3) + (2 .* (3 .^ (1 ./ 2) ./ 12 + 1 ./ 4) .* (nds_1_1 + nds_2_1 - nds_3_1 - nds_4_1 - (3 .^ (1 ./ 2) .* nds_1_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_2_1) ./ 3 - (3 .^ (1 ./ 2) .* nds_3_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_4_1) ./ 3)) ./ (nds_1_1 .* nds_2_2 - nds_1_2 .* nds_2_1 - nds_1_1 .* nds_4_2 + nds_1_2 .* nds_4_1 + nds_2_1 .* nds_3_2 - nds_2_2 .* nds_3_1 + nds_3_1 .* nds_4_2 - nds_3_2 .* nds_4_1 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_2_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_2_1) ./ 3 - (2 .* 3 .^ (1 ./ 2) .* nds_1_1 .* nds_3_2) ./ 3 + (2 .* 3 .^ (1 ./ 2) .* nds_1_2 .* nds_3_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_4_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_4_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_2_1 .* nds_3_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_2_2 .* nds_3_1) ./ 3 - (3 .^ (1 ./ 2) .* nds_3_1 .* nds_4_2) ./ 3 + (3 .^ (1 ./ 2) .* nds_3_2 .* nds_4_1) ./ 3))) .* ((2 .* (3 .^ (1 ./ 2) ./ 12 - 1 ./ 4) .* (nds_1_1 - nds_2_1 - nds_3_1 + nds_4_1 + (3 .^ (1 ./ 2) .* nds_1_1) ./ 3 - (3 .^ (1 ./ 2) .* nds_2_1) ./ 3 + (3 .^ (1 ./ 2) .* nds_3_1) ./ 3 - (3 .^ (1 ./ 2) .* nds_4_1) ./ 3)) ./ (nds_1_1 .* nds_2_2 - nds_1_2 .* nds_2_1 - nds_1_1 .* nds_4_2 + nds_1_2 .* nds_4_1 + nds_2_1 .* nds_3_2 - nds_2_2 .* nds_3_1 + nds_3_1 .* nds_4_2 - nds_3_2 .* nds_4_1 + (3 .^ (1 ./ 2) .* nds_1_1 .* nds_2_2) ./ 3 - (3 .^ (1 ./ 2) .* nds_1_2 .* nds_2_1) ./ 3 - (2 .* 3 .^ (1 ./ 2) .* nds_1_1 .* nds_3_2) ./ 3 + (2 .*